export const addPostcreateActin = () => ({ type: "ADDPOST" });

export const onPostChangecreateActin = (text) => ({
  type: "NEWPOST",
  newChange: text,
});

const messegDataReducer = (state, action) => {
  if (action.type === "ADDPOST") {
    let newPost = {
      id: 5,
      messege: this._state.messege.newChanges,
      like: 23,
    };
    state.messege.messegData.push(newPost);
    state.messege.newChanges = "";
  } else if (action.type === "NEWPOST") {
    state.messege.newChanges = action.newChange;
  }

  return state;
};

export default messegDataReducer;
